var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年9月30日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年9月30日 倫敦，白教堂 <color=#ffd34c>深夜</color>","SCN":"1888年9月30日 伦敦，白教堂 <color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"낙서가 남아있어……. 심야의 살인마 짓이야. 벌써 세번째라고……!","JPN":"落書きが残っている……深夜の殺人鬼の仕業だ。もう3回目だよ……！","ENG":"Another writing was left behind... It's the Midnight Killer's doing. It's already his third victim...!","TWN":"有塗鴉留下……是午夜殺人魔幹的。已經是第三次了……！"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"쯧쯧, 그러게 젊은 여자가 밤에 뭐 한다고 돌아다녀? 인과응보야 인과응보.","JPN":"若い女が夜の街を出歩いて何をしてたのやら……自業自得だな。","ENG":"Tsk, tsk. Why would a young woman be out so late? You get what you ask for.","TWN":"嘖嘖，年輕女孩晚上到處亂跑，能有什麼好事？這是報應，報應。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"심야의 살인마는 이능력자만 죽인다면서? 그럼, 이번에도…….","JPN":"深夜の殺人鬼が殺すのは異能力者だけなんだって？　じゃあ、今回も……","ENG":"Doesn't the Midnight Killer only kill Supernaturals? Then, this time...","TWN":"午夜殺人魔只殺超能力者吧？那麼，這次也是……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"거기! 현장을 훼손하지 마세요!","JPN":"そこ！　現場から離れなさい！","ENG":"Hey! Don't damage the scene!","TWN":"喂！不要破壞現場！"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"자, 비키세요! 수사에 방해가 됩니다.","JPN":"さあさあ、退いてください。捜査の邪魔です。","ENG":"Hey, get out of the way! You're interfering with the investigation.","TWN":"讓開！不要妨礙調查。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"음? 당신은?","JPN":"ん？　あなたは？","ENG":"Hmm? You are...","TWN":"嗯？你是？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다들 반갑네. 스코틀랜드 야드 여러분.","JPN":"やあ、スコットランドヤードの皆さん。","ENG":"Nice to meet you all, officers of Scotland Yard.","TWN":"大家好啊。蘇格蘭場的各位。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"칙령을 받고 사건을 수사중인 프레드릭 애버라인 경위라고 한다네.","JPN":"勅命がくだり事件を捜査しているフレデリック・アバーライン警部補だ。","ENG":"I am Lieutenant Fredrick Abberline, the one in charge of the case by royal decree.","TWN":"我是奉命調查案件的弗雷德里克·艾伯林警官。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"기, 기다리고 있었습니다. 애버라인 경위.","JPN":"お、お待ちしてました。アバーライン警部補。","ENG":"W-we've been waiting for you. Lieutenant Abberline.","TWN":"等，等著你呢，艾伯林警官。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_CAP","text":{"KOREA":"현장은 이쪽입니다, 어서.","JPN":"現場はこちらです。どうぞ。","ENG":"The scene is this way.","TWN":"現場在這裡，快這邊請。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐야? 왜 경감님께서 경위한테 쩔쩔매는 거지?","JPN":"なんだ？　なんで警視が警部補に頭を下げる？","ENG":"Huh? Why is the Captain so intimidated by that Lieutenant?","TWN":"什麼呀？為什麼督察要對一個警官畏畏縮縮的？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"멍청아, 애버라인이라는 이름을 대면 무조건 현장에 들여보내라는 보고 못 들었어?","JPN":"バカ、アバーラインという名前を聞いたら黙って現場に入れろって指示を忘れたのか？","ENG":"You idiot. Weren't you told to let the person named Abberline inspect the scene without asking any questions?","TWN":"笨蛋，沒聽上面說只要聽到艾伯林的名字就一定要讓他進去嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐? 그럼 저 사람이 그…….","JPN":"え？　じゃあ、あの人が……","ENG":"What? Then that's...","TWN":"嗯？所以那個人是……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사인은 날카로운 금속 흉기에 의한 척살.","JPN":"死因は鋭い金属の凶器による刺殺。","ENG":"The cause of death was a fatal wound with a sharp metal weapon.","TWN":"死因是被鋒利的金屬兇器刺殺。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자상이 많았던 이전 사건들과는 달라. 거의 단칼에 절명했어. 범행을 서두른 모양이군.","JPN":"刺傷が多く残っていた前回の事件とは違う。ほぼ一撃で絶命した。犯行を急いだようだな。","ENG":"The victims from previous cases had numerous stab wounds. But this one died with one strike. The murderer must have been in a hurry.","TWN":"和之前有很多刺傷的情況不同，這次幾乎是一刀斃命。看來兇手行兇時很匆忙。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"훼손된 신체는 좌측 <color=#ffd34c>대퇴부</color>. 아마도 여기가 증표가 새겨진 곳이겠지.","JPN":"損傷部位は左<color=#ffd34c>大腿部</color>。おそらくここに印があったのだろう。","ENG":"The mutilated body part was her left <color=#ffd34c>thigh</color>. It should be where her mark was.","TWN":"被破壞的身體部位是左側<color=#ffd34c>大腿</color>。大概這裡就是存在印記的地方吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"Also...","TWN":"還有……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현장에 남아있는 낙서는…….","JPN":"現場に残っている落書きは……","ENG":"The writing left behind at the scene is...","TWN":"現場留下的塗鴉是……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 역시 그렇군.","JPN":"ああ、やはりそうだな。","ENG":"Right, just as I expected.","TWN":"嗯，果真如此。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제야 그 의미가 분명해졌어. 그렇다면 다음 희생자는 아마도…….","JPN":"やっと意味がわかってきた。では次の犠牲者は……","ENG":"Now, the meaning is clear. Then the next victim will probably be...","TWN":"現在意義已經明確了。那麼下一個犧牲者可能是……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건? <color=#ffd34c>유리 조각</color>……?","JPN":"これは？　<color=#ffd34c>ガラスの破片</color>……？","ENG":"This is... a <color=#ffd34c>glass shard</color>...?","TWN":"這是塊<color=#ffd34c>玻璃碎片</color>……？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};